class Solution(object):
    def minOperations(self, nums):
        stack = []
        ops = 0
        for v in nums:
            if v == 0:
                stack = []
                continue
            while stack and stack[-1] > v:
                stack.pop()
            if not stack or stack[-1] != v:
                stack.append(v)
                ops += 1
        return ops
